const body = ($input.first().json.body) || {};
const etapa = body.etapa || 'Educacional 1';
const registros = Array.isArray(body.registros) ? body.registros : [];
const reEmail = /^[^@\s]+@[^@\s]+\.[^@\s]+$/;
const out = [];
for (const r of registros) {
  const email = String(r.email || r.Email || '').trim().toLowerCase();
  if (!reEmail.test(email)) continue;
  const nome = String(r.nome || r.Nome || r.nome_cliente || '').trim();
  const empresa = String(r.empresa || r.Empresa || r.empregador || '').trim();
  let vr = (r.valor != null) ? r.valor : ((r.valor_total_saldo != null) ? r.valor_total_saldo : (r.Valor || ''));
  let valor = 0; const vraw = String(vr).trim();
  if (vraw) { let s = vraw.replace(/[^0-9.,-]/g, ''); if (s.indexOf(',') > -1) { s = s.replace(/\./g, '').replace(',', '.'); } valor = parseFloat(s); if (isNaN(valor)) valor = 0; }
  const draw = String(r.vencimento || r.Vencimento || r.dt_vencimento || '').trim();
  let venc = '';
  if (draw) { let dt; if (draw.indexOf('/') > -1) { dt = DateTime.fromFormat(draw, 'dd/LL/yyyy'); if (!dt.isValid) dt = DateTime.fromFormat(draw, 'd/L/yyyy'); } else { dt = DateTime.fromISO(draw); } if (dt && dt.isValid) venc = dt.toISODate(); }
  out.push({ json: { nome: nome, email: email, empresa: empresa, valor: valor, vencimento: venc, etapa: etapa } });
}
return out;
